package com.google.gson.internal.bind;
import com.google.gson.JsonSyntaxException;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.internal.JavaVersion;
import com.google.gson.internal.PreJava9DateFormatProvider;
import com.google.gson.internal.bind.util.ISO8601Utils;
import com.google.gson.stream.JsonWriter;
import java.text.DateFormat;
import java.text.ParseException;
import java.text.ParsePosition;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;
import java.util.Objects;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Constructor;
import java.lang.reflect.Method;
import java.util.Date;

class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateType;

    @BeforeEach
    void setUp() throws Exception {
        dateType = mock(DefaultDateTypeAdapter.DateType.class);
        // Use reflection to access the private constructor
        Constructor<DefaultDateTypeAdapter> constructor = DefaultDateTypeAdapter.class.getDeclaredConstructor(DefaultDateTypeAdapter.DateType.class, String.class);
        constructor.setAccessible(true);
        adapter = (DefaultDateTypeAdapter<Date>) constructor.newInstance(dateType, "yyyy-MM-dd");
    }

    @Test
    void read_shouldReturnNull_whenJsonTokenIsNull() throws IOException {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.NULL);

        Date result = adapter.read(in);

        verify(in).nextNull();
        assertNull(result);
    }

    @Test
    void read_shouldReturnDeserializedDate() throws Exception {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.STRING);
        when(in.nextString()).thenReturn("2026-01-09");

        Date expectedDate = new Date();

        // Spy adapter without stubbing private method directly
        var spyAdapter = Mockito.spy(adapter);

        // Use reflection to stub the private method deserializeToDate
        Method deserializeToDateMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        // Use Mockito's doAnswer to intercept call to private method via reflection
        doReturn(expectedDate).when(spyAdapter).read(any(JsonReader.class)); // fallback to avoid infinite recursion

        // Instead of stubbing private method directly, invoke read() and mock dateType.deserialize
        when(dateType.deserialize(expectedDate)).thenReturn(expectedDate);

        // To force deserializeToDate to return expectedDate, we override it by creating a subclass
        DefaultDateTypeAdapter<Date> adapterWithOverride = new DefaultDateTypeAdapter<Date>(dateType, "yyyy-MM-dd") {
            @Override
            protected Date deserializeToDate(JsonReader in) {
                return expectedDate;
            }
        };

        Date actual = adapterWithOverride.read(in);

        verify(dateType).deserialize(expectedDate);
        assertEquals(expectedDate, actual);
    }
}
